import React from "react";
import ReactDom from "react-dom/client";
import "./styles.css";

function App() {
  return (
    <div className="card">
      <Avatar />
      <div className="data">
        <Intro />

        <SkillList />
      </div>
    </div>
  );
}

function Avatar() {
  return (
    <div>
      <img
        src="./my-photo.jpg"
        alt="a guy looking at the camera"
        className="avatar"
      />
    </div>
  );
}

function Intro() {
  return (
    <div>
      <h1>Mehdi Sadeghi</h1>
      <p>
        Junior Front-end developer and English teacher at Barbod English
        institute. when not coding or teaching, I like to watch football or hit
        the gym, or just enjoy hanging out eith friends.
      </p>
    </div>
  );
}

function SkillList() {}

const rootElement = document.getElementById("root");
const root = ReactDom.createRoot(rootElement);

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);
